"""
This is the main module to launch the program
"""

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("red"), Player("black")]
        self.current_player_index = 0

    def run(self):
        while True:
            current_player = self.players[self.current_player_index]
            move = InputParser.get_move(current_player)
            if move is None:
                break
            self.board.make_move(move)
            self.switch_turn()
            if self.check_win():
                OutputGenerator.display_message(f"Player {current_player.color} wins!")
                break

    def switch_turn(self):
        self.current_player_index = 1 - self.current_player_index

    def check_win(self):
        return False  # Implement win detection logic here


