class Piece:
    def __init__(self, position, color):
        self.position = position
        self.color = color
        self.is_king = False


class Player:
    def __init__(self, color):
        self.color = color
        self.captured_pieces = []


class Move:
    def __init__(self, start, end):
        self.start = start
        self.end = end


class InputParser:
    @staticmethod
    def get_move(player):
        while True:
            input_str = input(f"Player {player.color}, enter move (e.g., a1-b2): ")
            try:
                start, end = input_str.split('-')
                return Move(start, end)
            except ValueError:
                print("Invalid input. Please try again.")


class OutputGenerator:
    @staticmethod
    def display_message(message):
        print(message)
